:root {
  --bg-color: #f4f7f6;
  --card-bg: #ffffff;
  --primary: #2c3e50;
  --accent: #3498db;
  --text: #333;
  --text-dim: #7f8c8d;
  --border: #ddd;
  /* Standardized Palette */
  --danger: #e74c3c; /* Red */
  --warning: #f39c12; /* Orange */
  --info: #3498db; /* Blue */
  --success: #27ae60; /* Green */
}

/* 1. Add this to ensure no default browser white space */
body {
  margin: 0;
  padding: 0;
}

/* 2. Update the main container to remove outer padding */
.governance-container {
  background-color: var(--bg-color);
  color: var(--text);
  font-family: "Segoe UI", Tahoma, Geneva, Verdana, sans-serif;
  padding: 0;
  min-height: 100vh;
}

/* 3. Update the wrapper to stretch full width */
.governance-wrapper {
  max-width: 100%;
  margin: 0;
  padding: 20px;
}

.gov-header {
  position: relative;
  display: flex;
  justify-content: center;
  align-items: center;
  margin-bottom: 30px;
  border-bottom: 1px solid var(--border);
  padding-bottom: 20px;
}

.brand {
  text-align: center;
}

.brand h1 {
  margin: 0;
  color: var(--primary);
  font-size: 1.8rem;
}

.brand .subtitle {
  color: #000000;
  font-size: 1rem;
  margin: 8px 0 0 0;
}

.risk-badge {
  position: absolute;
  right: 0;
  padding: 8px 20px;
  border-radius: 9999px;
  font-weight: bold;
  font-size: 1rem;
  white-space: nowrap;
}

.risk-badge.low {
  background: var(--success);
  color: #ffffff;
}

.risk-badge.high {
  background: var(--danger);
  color: #ffffff;
}

.risk-badge.med {
  background: var(--warning);
  color: #ffffff;
}

.gov-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 20px;
  margin-bottom: 40px;
}

.gov-card {
  background: var(--card-bg);
  padding: 20px;
  border-radius: 8px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
  text-align: center;
  /* Base border - color is overridden below */
  border-top: 4px solid #ddd;
}

/* --- COLORFUL BOXES LOGIC --- */
/* 1st Box: Red (High Risk) */
.gov-card:nth-child(1) {
  border-top-color: var(--danger);
}

/* 2nd Box: Orange (Warning) */
.gov-card:nth-child(2) {
  border-top-color: var(--warning);
}

/* 3rd Box: Blue (Info) */
.gov-card:nth-child(3) {
  border-top-color: var(--info);
}

/* 4th Box: Green (Success) */
.gov-card:nth-child(4) {
  border-top-color: var(--success);
}

.gov-card label {
  display: block;
  color: var(--text-dim);
  font-size: 0.9rem;
  margin: 0;
  text-transform: uppercase;
  font-weight: bold;
  letter-spacing: 1px;
}

.gov-card .value {
  font-size: 2.2rem;
  font-weight: bold;
  color: var(--text);
  margin: 10px 0 0;
}

.gov-card small {
  color: var(--text-dim);
  font-size: 0.8rem;
  display: block;
  margin-top: 6px;
}

.audit-section {
  background: var(--card-bg);
  border-radius: 8px;
  overflow: hidden;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
  padding: 20px;
  /* Added Blue Accent for consistency */
  border-top: 3px solid var(--info);
}

.audit-section h3 {
  margin-top: 0;
  margin-bottom: 15px;
  font-size: 1.1rem;
  color: var(--primary);
  border-bottom: 2px solid var(--bg-color);
  padding-bottom: 10px;
}

.table-scroll {
  overflow-x: auto;
}

table {
  width: 100%;
  border-collapse: collapse;
  margin-top: 10px;
}

th {
  background-color: #f8f9fa;
  color: var(--primary);
  text-align: left;
  padding: 12px;
  font-size: 0.9rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  border-bottom: 2px solid var(--border);
}

td {
  padding: 12px;
  border-bottom: 1px solid var(--border);
  font-size: 1rem;
  color: var(--text);
  vertical-align: middle;
}

tr:hover {
  background-color: #f1f1f1;
}

.risk-tag {
  padding: 4px 8px;
  border-radius: 4px;
  font-size: 0.85rem;
  font-weight: bold;
  text-transform: uppercase;
}

.risk-high {
  background: #f8d7da;
  color: #721c24;
  border: 1px solid #f5c6cb;
}

.risk-warning {
  background: #fff3cd;
  color: #856404;
  border: 1px solid #ffeeba;
}

.risk-none {
  background: #d4edda;
  color: #155724;
  border: 1px solid #c3e6cb;
}

code {
  background: #f0f0f0;
  padding: 2px 5px;
  border-radius: 3px;
  color: #d35400;
  font-family: monospace;
}

