appsmith.onReady(renderDashboard);
appsmith.onModelChange(renderDashboard);
function renderDashboard() {
  // FIX 1: Read from 'cookies' as mapped in your Default Model
  let rawData = appsmith.model.cookies;

  // Safety: Handle if data is passed as a string
  if (typeof rawData === 'string') {
    try {
      rawData = JSON.parse(rawData);
    } catch (e) {
      console.error("Parse error", e);
    }
  }
  // Safety: Handle nested 'fileData' wrapper if present
  if (rawData && rawData.fileData && typeof rawData.fileData === 'string') {
    try {
      rawData = JSON.parse(rawData.fileData);
    } catch (e) {
      console.error("Nested parse error", e);
    }
  }

  // Safety: Handle Array Root (Unwrap)
  if (Array.isArray(rawData)) {
    rawData = rawData.length > 0 ? rawData[0] : {};
  }
  const data = rawData || {};

  // --- SAFE EXTRACTION START ---

  // 1. Shadow AI / Trackers (Using total_trackers from the APK payload)
  let trackerCount = data.total_trackers || 0;
  if (!trackerCount) {
    if (typeof data.trackers === 'number') {
      trackerCount = data.trackers;
    } else if (Array.isArray(data.trackers)) {
      trackerCount = data.trackers.length;
    } else if (data.trackers && typeof data.trackers === 'object') {
      trackerCount = Object.keys(data.trackers).length;
    }
  }

  // 2. Security Score
  let score = data.security_score || 0;

  // 3. Dynamic Dangerous Permissions extraction
  let dangerousPerms = [];
  if (data.permissions && typeof data.permissions === 'object') {
    Object.keys(data.permissions).forEach(k => {
      const val = data.permissions[k];
      // MobSF usually labels dangerous permissions in the status
      if (val && (val.status === 'dangerous' || typeof val === 'string' && val.includes('dangerous'))) {
        dangerousPerms.push(k);
      }
    });
  }
  // Fallback for older MobSF schemas
  if (dangerousPerms.length === 0 && data.malware_permissions) {
    dangerousPerms = data.malware_permissions.top_malware_permissions || [];
  }
  const dangerousCount = dangerousPerms.length || data.malware_permissions?.total_malware_permissions || 0;

  // 4. Manifest Findings
  const findings = data.manifest_analysis?.manifest_findings || [];

  // --- SAFE EXTRACTION END ---

  const tableBody = document.querySelector('#audit-body');
  if (tableBody) tableBody.innerHTML = "";

  // Update Cards
  document.getElementById('shadow-ai-count').textContent = trackerCount;
  document.getElementById('bridge-count').textContent = dangerousCount;

  // DLP Logic (Manifest Signal)
  const dlpEl = document.getElementById('dlp-status');
  const dlpSub = document.getElementById('dlp-sub');
  const backupFinding = findings.find(f => f.rule === "allow_backup" || f.title?.includes("backup"));
  if (backupFinding) {
    dlpEl.textContent = "Open Signal";
    dlpEl.style.color = "#e74c3c";
    dlpSub.textContent = "Backup Allowed (Risk)";
  } else {
    dlpEl.textContent = "Controlled";
    dlpEl.style.color = "#27ae60";
    dlpSub.textContent = "Backup Restricted";
  }

  // Integrity Score
  const scoreEl = document.getElementById('integrity-score');
  scoreEl.textContent = `${score}%`;
  scoreEl.style.color = score < 50 ? "#e74c3c" : score < 80 ? "#f39c12" : "#27ae60";

  // Risk Badge
  const badge = document.getElementById('risk-score');
  if (score < 50 || dangerousCount > 5) {
    badge.textContent = "Threat Signal: CRITICAL";
    badge.className = "risk-badge high";
  } else if (score < 80 && score > 0) {
    badge.textContent = "Threat Signal: ELEVATED";
    badge.className = "risk-badge med";
  } else if (score >= 80) {
    badge.textContent = "Threat Signal: NOMINAL";
    badge.className = "risk-badge low";
  }

  // Build Audit Table
  const auditItems = [];

  // Push Manifest signals
  findings.forEach(f => {
    auditItems.push({
      name: f.title || f.rule || "Manifest Rule Flaw",
      type: "MANIFEST SIGNAL",
      layer: "Configuration",
      risk: (f.severity || "INFO").toUpperCase(),
      action: "Review Config"
    });
  });

  // Push Dangerous Permissions signals
  dangerousPerms.forEach(p => {
    const permName = p.split('.').pop();
    auditItems.push({
      name: `android.permission.${permName}`,
      type: "DATA EGRESS SIGNAL",
      layer: "OS Bridge",
      risk: "HIGH",
      action: "Revoke / Justify"
    });
  });

  // Push Tracker signals
  if (trackerCount > 0) {
    auditItems.push({
      name: `${trackerCount} Tracker SDKs`,
      type: "SHADOW AI SIGNAL",
      layer: "Third-Party Code",
      risk: trackerCount > 100 ? "HIGH" : "MEDIUM",
      action: "Audit Dependencies"
    });
  }

  // Sort High risk to top
  const riskMap = {
    "CRITICAL": 4,
    "HIGH": 3,
    "WARNING": 2,
    "MEDIUM": 2,
    "INFO": 1
  };
  auditItems.sort((a, b) => (riskMap[b.risk] || 0) - (riskMap[a.risk] || 0));

  // Limit to top 15 in the table to keep the UI clean
  const topAuditItems = auditItems.slice(0, 15);

  // Render
  if (tableBody) {
    if (topAuditItems.length === 0) {
      tableBody.innerHTML = `<tr><td colspan="5" style="text-align:center; padding:20px; color:#999;">No signals detected. Waiting for analysis...</td></tr>`;
    } else {
      topAuditItems.forEach(item => {
        const row = document.createElement('tr');
        let riskClass = "risk-none";
        if (item.risk === "HIGH" || item.risk === "CRITICAL") riskClass = "risk-high";else if (item.risk === "WARNING" || item.risk === "MEDIUM") riskClass = "risk-warning";
        row.innerHTML = `
                    <td><code>${item.name}</code></td>
                    <td>${item.type}</td>
                    <td>${item.layer}</td>
                    <td><span class="risk-tag ${riskClass}">${item.risk}</span></td>
                    <td style="font-weight:bold; color:var(--accent)">${item.action}</td>
                `;
        tableBody.appendChild(row);
      });
    }
  }
}

